using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly string[] _labels;

    public TicketController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        IConfiguration configuration)
    {
        _predictionPool = predictionPool;

        var modelPath = configuration.GetValue<string>("ML:ModelPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        var mlContext = new MLContext();
        var model = mlContext.Model.Load(modelPath, out _);

        var labelColumn = model.GetOutputSchema(SchemaDefinition.Create(typeof(TicketData)))
            .GetColumnOrNull("Category");
        _labels = labelColumn!.Value.GetKeyValues<ReadOnlyMemory<char>>()
            .Select(v => v.ToString()).ToArray();
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketClassificationResult
        {
            Category = prediction.Category,
            Confidence = confidence
        });
    }
}

